export function getRecommendations(selectedTags) {
  const scores = destinations.map((dest) => {
    const score = dest.tags.filter((tag) => selectedTags.includes(tag)).length;
    return { ...dest, score };
  });
  return scores.sort((a, b) => b.score - a.score).slice(0, 3);
}